// To run this code you need to install the following dependencies:
// npm install @google/genai mime
// npm install -D @types/node

import {
  GoogleGenAI,
} from '@google/genai';

async function main() {
  const ai = new GoogleGenAI({
    apiKey: process.env['GEMINI_API_KEY'],
  });
  const tools = [
    { urlContext: {} },
    { codeExecution: {} },
  ];
  const config = {
    temperature: 0.1,
    thinkingConfig: {
      thinkingLevel: ThinkingLevel.HIGH,
    },
    mediaResolution: 'MEDIA_RESOLUTION_HIGH',
    tools,
    systemInstruction: [
        {
          text: `You are a strict, deterministic Optical Character Recognition (OCR) data extraction engine for an SQA testing harness. Your purpose is to analyze screenshots of various game UIs and extract financial metrics.

STRICT RULES OF ENGAGEMENT:
1. Extract the numerical values for the metrics requested by the user.
2. Strip all currency symbols (e.g., $, ₹, €), commas, and spaces from the extracted text.
3. Cast the extracted strings into strictly typed JSON Numbers (floats). Example: "₹10,230.00" becomes 10230.00.
4. If a specific metric is not visible on the screen, default its value to 0.00.
5. NEVER output markdown formatting, backticks, conversational filler, or explanations.
6. Your output MUST be a raw, parsable JSON object matching this exact schema:
{
  "balance": <number>,
  "bet": <number>,
  "win": <number>
}`,
        }
    ],
  };
  const model = 'gemini-3.1-pro-preview';
  const contents = [
    {
      role: 'user',
      parts: [
        {
          inlineData: {
            data: '',
            mimeType: `image/jpeg`,
          },
        },
        {
          text: `Game Type: Slot Machine
Analyze this screenshot and extract the current balance, bet, and win amounts based on your system instructions.`,
        },
      ],
    },
    {
      role: 'model',
      parts: [
        {
          text: `**Defining the Parameters**

I'm now zeroing in on defining the exact parameters. My focus is on ensuring the JSON output is clean and precise – just the requested data: 'balance', 'bet', and 'win'. I'm aiming for no extraneous markdown or extra details, and a clear, well-formed JSON object. This should streamline integration.


`,
        },
        {
          text: `{
  "balance": 791457.05,
  "bet": 7.50,
  "win": 0.00
}`,
        },
      ],
    },
    {
      role: 'user',
      parts: [
        {
          text: `INSERT_INPUT_HERE`,
        },
      ],
    },
  ];

  const response = await ai.models.generateContentStream({
    model,
    config,
    contents,
  });
  let fileIndex = 0;
  for await (const chunk of response) {
    if (!chunk.candidates || !chunk.candidates[0].content || !chunk.candidates[0].content.parts) {
      continue;
    }
    if (chunk.candidates[0].content.parts[0].text) {
      console.log(chunk.candidates[0].content.parts[0].text);
    }
    if (chunk.candidates[0].content.parts[0].executableCode) {
      console.log(chunk.candidates[0].content.parts[0].executableCode);
    }
    if (chunk.candidates[0].content.parts[0].codeExecutionResult) {
      console.log(chunk.candidates[0].content.parts[0].codeExecutionResult);
    }
  }
}

main();


